import 'package:flutter/material.dart';import '../../design_system/app_colors.dart';import '../../design_system/app_spacing.dart';import '../../design_system/app_typography.dart';import '../../design_system/ds_fab.dart';import '../../design_system/ds_input_field.dart';import '../../design_system/ds_list_item.dart';import '../../models/transaction.dart';import '../../services/mock_data_service.dart';import 'transaction_detail_screen.dart';class TransactionListScreen extends StatefulWidget {  final String title;  final List<Transaction>? transactions;  const TransactionListScreen({    super.key,    this.title = 'All Transactions',    this.transactions,  });  @override  State<TransactionListScreen> createState() => _TransactionListScreenState();}@overrideclass _TransactionListScreenState extends State<TransactionListScreen> {  late List<Transaction> _displayTransactions;  final TextEditingController _searchController = TextEditingController();  @override  void initState() {    super.initState();    _displayTransactions = widget.transactions ?? MockDataService.transactions;    _searchController.addListener(_filterTransactions);  }  @override  void dispose() {    _searchController.removeListener(_filterTransactions);    _searchController.dispose();    super.dispose();  }  void _filterTransactions() {    final query = _searchController.text.toLowerCase();    setState(() {      _displayTransactions = (widget.transactions ?? MockDataService.transactions)          .where((t) =>                t.merchant.toLowerCase().contains(query) ||                t.category.name.toLowerCase().contains(query) ||                t.description?.toLowerCase().contains(query) == true)          .toList();    });  }  @override  Widget build(BuildContext context) {    return Scaffold(      backgroundColor: AppColors.background,      appBar: AppBar(        title: Text(widget.title, style: AppTypography.h2),        actions: [          DsIconButton(            icon: Icons.filter_list_outlined,            onPressed: () {              ScaffoldMessenger.of(context).showSnackBar(                const SnackBar(content: Text('Filter options coming soon!')),              );            },          ),          SizedBox(width: AppSpacing.paddingSmall),        ],      ),      body: Column(        children: [          Padding(            padding: const EdgeInsets.symmetric(horizontal: AppSpacing.paddingLarge),            child: DsInputField(              controller: _searchController,              hintText: 'Search transactions...',              suffixIcon: _searchController.text.isNotEmpty                  ? DsIconButton(                      icon: Icons.clear,                      onPressed: () {                        _searchController.clear();                        _filterTransactions();                      },                      size: AppSpacing.iconSizeMedium,                      backgroundColor: Colors.transparent,                      iconColor: AppColors.textSecondary,                    )                  : null,            ),          ),          SizedBox(height: AppSpacing.paddingMedium),          Expanded(            child: ListView.builder(              itemCount: _displayTransactions.length,              itemBuilder: (context, index) {                final transaction = _displayTransactions[index];                final isNegative = transaction.amount < 0;                return DsListItem(                  leading: Container(                    width: AppSpacing.categoryIconSize,                    height: AppSpacing.categoryIconSize,                    decoration: BoxDecoration(                      color: transaction.category.color.withOpacity(0.2),                      borderRadius: BorderRadius.circular(AppSpacing.borderRadiusSmall),                    ),                    child: Icon(transaction.category.icon, color: transaction.category.color),                  ),                  title: transaction.merchant,                  subtitle:                    '${transaction.category.name} • ${transaction.date.day}/${transaction.date.month}/${transaction.date.year}',                  trailingText: MockDataService.formatCurrency(transaction.amount),                  trailingTextColor: isNegative ? AppColors.error : AppColors.success,                  onTap: () {                    Navigator.of(context).push(MaterialPageRoute(                      builder: (_) => TransactionDetailScreen(transaction: transaction),                    ));                  },                );              },            ),          ),        ],      ),      floatingActionButton: DsFab(        icon: Icons.add,        onPressed: () {          ScaffoldMessenger.of(context).showSnackBar(            const SnackBar(content: Text('Add Manual Transaction coming soon!')),          );        },      ),    );  }}